const input = $json;
const ergebnis = (input.customFields || {})['custom.cf_Bp0LGE1a2Am7BlHszQNtV7KuTpVYDthbiKOetsFkcUQ'] || '';

const statusMap = {
  '1 - Kunde': 'stat_bMeIa40jGWwjbA5bOJpdIGgBk7QFWa1nlhsA9hVJg1J',
  '2 - Folgetermin': 'stat_bMeIa40jGWwjbA5bOJpdIGgBk7QFWa1nlhsA9hVJg1J',
  '3 - Follow-up': 'stat_bMeIa40jGWwjbA5bOJpdIGgBk7QFWa1nlhsA9hVJg1J',
  '4 - Verloren': 'stat_2NjdTtgLsl931S2nrmOLTK7IWW7KV0JVsiTwS7zexT4',
  '5 - Unqualifiziert': 'stat_0o8JNmzSa6GiQH5yEZ424xT9B08NGTia4U3VxxzssMB'
};

const statusId = statusMap[ergebnis] || 'stat_bMeIa40jGWwjbA5bOJpdIGgBk7QFWa1nlhsA9hVJg1J';

const now = new Date();
const closeDate = new Date(now.getTime() + 7 * 24 * 60 * 60 * 1000);
const closeDateStr = closeDate.toISOString().split('T')[0];

const date = new Date(input.dateCreated || now.toISOString());
const dayStart = new Date(date.getFullYear(), date.getMonth(), date.getDate()).toISOString();
const dayEnd = new Date(date.getFullYear(), date.getMonth(), date.getDate() + 1).toISOString();

return [{
  json: {
    ...input,
    ergebnis,
    statusId,
    closeDateStr,
    dayStart,
    dayEnd,
    opportunityBody: {
      lead_id: input.leadId,
      status_id: statusId,
      value: 300000,
      value_period: 'one_time',
      value_currency: 'EUR',
      confidence: 33,
      date_created: input.dateCreated,
      close_date: closeDateStr,
      note: 'Automatisch erstellt durch EG stattgefunden Activity',
      user_id: input.userId
    }
  }
}];

const staticData = this.getWorkflowStaticData('node');
staticData.loopCount = 0;
return [{ json: { loopCount: 0 } }];

const response = $('GET Calls').first().json;
const callsData = response.data || [];
const calls = callsData.filter(c => c.recording_url);

const staticData = this.getWorkflowStaticData('node');
const loopCount = (staticData.loopCount || 0);

if (calls.length === 0 && loopCount < 10) {
  staticData.loopCount = loopCount + 1;
  return [{ json: { hasRecordings: false, loopCount: loopCount + 1, maxReached: false } }];
}

if (calls.length === 0 && loopCount >= 10) {
  return [{ json: { hasRecordings: false, loopCount: loopCount, maxReached: true, calls: [] } }];
}

return [{ json: { hasRecordings: true, loopCount: loopCount, maxReached: false, calls } }];

const meta = $('Prepare Data').first().json;
const calls = $('Check Recordings').first().json.calls || [];

function uuid() {
  return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, c => {
    const r = Math.random() * 16 | 0;
    return (c === 'x' ? r : (r & 0x3 | 0x8)).toString(16);
  });
}

const transcripts = [];

for (let i = 0; i < calls.length; i++) {
  const call = calls[i];
  if (i > 0) await new Promise(r => setTimeout(r, 2000));

  try {
    const audioBuffer = await this.helpers.httpRequest({
      method: 'GET',
      url: call.recording_url,
      headers: {
        'Authorization': 'Basic YXBpXzJKd0JqaHMwYmZCUmJ5d3dHeXA0blUuMWlWV0NZVUUyRzE3NWh6NjJmNEJMRzo='
      },
      encoding: 'arraybuffer'
    });

    const boundary = '----n8nBoundary' + Date.now() + i;
    const modelPart = '--' + boundary + '\r\nContent-Disposition: form-data; name="model"\r\n\r\nwhisper-1\r\n';
    const fileHeader = '--' + boundary + '\r\nContent-Disposition: form-data; name="file"; filename="recording.mp3"\r\nContent-Type: audio/mpeg\r\n\r\n';
    const footer = '\r\n--' + boundary + '--\r\n';

    const bodyBuffer = Buffer.concat([
      Buffer.from(modelPart),
      Buffer.from(fileHeader),
      Buffer.from(audioBuffer),
      Buffer.from(footer)
    ]);

    const whisperResult = await this.helpers.httpRequest({
      method: 'POST',
      url: 'https://api.openai.com/v1/audio/transcriptions',
      headers: {
        'Authorization': 'Bearer ' + $env.OPENAI_API_KEY,
        'Content-Type': 'multipart/form-data; boundary=' + boundary
      },
      body: bodyBuffer
    });

    const transcriptText = typeof whisperResult === 'string' ? whisperResult : (whisperResult.text || JSON.stringify(whisperResult));

    transcripts.push({
      source_type: 'call',
      source_id: uuid(),
      content: transcriptText,
      call_type: 'erstgespraech',
      url: call.recording_url,
      synced_at: new Date().toISOString()
    });
  } catch (e) {
    continue;
  }
}

return [{ json: { transcripts, count: transcripts.length } }];

